-- Discord (6)
('discord', 'devuser42',    'Workers seems to randomly drop connections after about 30 seconds of inactivity. Happening in production for us. Is this a known issue?',                                                                       '2026-04-24T09:12:00Z', 'negative', 8,  '["Workers","Reliability","Production Issue"]',           1),
('discord', 'cloudbuilder', 'Just deployed my first Workers site using D1 and it was honestly way easier than expected. The wrangler CLI is super smooth.',                                                                                 '2026-04-24T14:30:00Z', 'positive', 2,  '["Workers","D1","Developer Experience"]',                1),
('discord', 'mlhacker99',   'Anyone else getting rate limited by Workers AI? Trying to run llama-3 for a batch job and hitting limits constantly.',                                                                                         '2026-04-25T11:05:00Z', 'negative', 7,  '["Workers AI","Rate Limits","Batch Processing"]',        1),
('discord', 'cf_watcher',   'The new Workflows feature is interesting but the docs are really sparse. Would love more examples of real-world use cases.',                                                                                   '2026-04-25T16:44:00Z', 'neutral',  4,  '["Workflows","Documentation"]',                          1),
('discord', 'tsdev_',       'Wrangler types command does not update after adding a new KV binding. Have to delete and regenerate manually each time.',                                                                                      '2026-04-26T08:20:00Z', 'negative', 5,  '["Wrangler","TypeScript","Developer Experience"]',       1),
('discord', 'edge_enjoyer', 'R2 plus Workers combo is absolutely incredible for media serving. Sub-10ms globally. Cloudflare engineering is impressive.',                                                                                   '2026-04-26T19:55:00Z', 'positive', 1,  '["R2","Performance","Workers"]',                          1),

