('github',  'reporter_x',   'Bug: D1 returns null for LEFT JOIN when right table has no matching row instead of the expected null column values. Reproducible with simple schema.',                                                         '2026-04-24T10:00:00Z', 'negative', 9,  '["D1","SQL","Bug"]',                                     1),
('github',  'workflow_fan', 'Feature Request: Add support for scheduled Workflows with cron triggers. Having to manually trigger via fetch defeats the durable execution story.',                                                           '2026-04-25T13:15:00Z', 'neutral',  6,  '["Workflows","Cron","Feature Request"]',                 1),
('github',  'wrangler_dev', 'wrangler dev --remote fails with 401 when using service bindings across accounts. Works fine with --local flag.',                                                                                              '2026-04-25T17:30:00Z', 'negative', 7,  '["Wrangler","Service Bindings","Authentication"]',       1),
('github',  'llm_tester',   'Workers AI llama-3.1-8b-instruct context window appears capped at 2048 tokens despite documentation stating 8192.',                                                                                           '2026-04-26T09:40:00Z', 'negative', 8,  '["Workers AI","Documentation","LLM Context"]',           1),
('github',  'd1_user',      'Request: Improve error messages from D1 migrations. Currently shows generic SQL error without line numbers, very hard to debug.',                                                                              '2026-04-27T14:00:00Z', 'neutral',  5,  '["D1","Developer Experience","Error Messages"]',         1),
