('twitter', '@speedcheck',  'wrangler deploy took 4 minutes today. Usually under 30 seconds. Is something wrong with the deploy pipeline?',                                                                                                '2026-04-24T18:02:00Z', 'negative', 7,  '["Wrangler","Deployment","Performance"]',                1),
('twitter', '@costsavings', 'Moved image CDN to R2 plus Workers last week. Bill went from $800/mo to $40/mo. No other changes. Still in shock.',                                                                                           '2026-04-25T09:11:00Z', 'positive', 1,  '["R2","Pricing","CDN"]',                                 1),
('twitter', '@observ_dev',  'Please add a proper dashboard for Workers AI usage. No way to know how many tokens are burning until the monthly bill hits.',                                                                                  '2026-04-26T12:33:00Z', 'negative', 6,  '["Workers AI","Dashboard","Observability"]',             1),
('twitter', '@pipeliner',   'Every time I try to use D1 inside a Workflow step it times out. The CPU limit is way too restrictive for ML pipelines.',                                                                                       '2026-04-27T08:45:00Z', 'negative', 8,  '["D1","Workflows","CPU Limit"]',                         1),
('twitter', '@edgefan',     'Impressed by Workers cold start times. Under 1ms vs AWS Lambda 200ms plus for the same workload. Night and day difference.',                                                                                   '2026-04-28T15:20:00Z', 'positive', 1,  '["Workers","Performance","Cold Start"]',                 1),
