-- Support Tickets (6)
('support', 'ticket_8821',  'Intermittent 500 errors from Workers deployment. Logs show Worker exceeded CPU time limit but worker only does simple JSON parsing. Blocking production.',                                                     '2026-04-23T07:30:00Z', 'negative', 10, '["Workers","CPU Limit","Production Issue"]',             1),
('support', 'ticket_8834',  'Cannot find how to set environment variables per environment (staging vs production) in the new wrangler.jsonc format. Documentation only covers old wrangler.toml.',                                          '2026-04-24T11:00:00Z', 'neutral',  5,  '["Wrangler","Documentation","Environment Variables"]',  1),
('support', 'ticket_8850',  'Billing issue: charged for Workers AI tokens that were never returned due to timeout errors. Requesting credit for approximately 50000 tokens.',                                                               '2026-04-25T14:20:00Z', 'negative', 7,  '["Workers AI","Billing","Reliability"]',                 1),
('support', 'ticket_8861',  'D1 migrations failing on production but succeeding in dev. Error: SQLITE_CONSTRAINT_UNIQUE. Data should be clean. No way to inspect current migration state.',                                                 '2026-04-26T09:50:00Z', 'negative', 9,  '["D1","Migrations","Production Issue"]',                 1),
('support', 'ticket_8877',  'Dashboard asks to add a site before creating Workers. We only want serverless functions without a domain. Navigation is confusing for pure serverless developers.',                                            '2026-04-27T16:30:00Z', 'neutral',  4,  '["Dashboard","Onboarding","Developer Experience"]',     1),
('support', 'ticket_8892',  'Workers Secrets UI only allows setting one secret at a time. Please add bulk import from a .env file for teams managing many secrets.',                                                                        '2026-04-28T10:05:00Z', 'neutral',  5,  '["Workers","Secrets","Developer Experience"]',          1),

-- Community Forum (6)
('forum',   'forum_pm_guy', 'Best practices for handling Workers AI rate limits in production? Building a support bot and hitting limits during peak hours. Looking for patterns others have used.',                                         '2026-04-24T13:00:00Z', 'neutral',  5,  '["Workers AI","Rate Limits","Best Practices"]',          1),
('forum',   'workflow_n00b','Anyone successfully passed D1 results between Workflow steps? Getting serialization errors. Passing the D1 result object directly seems to cause silent failures.',                                            '2026-04-25T10:30:00Z', 'negative', 6,  '["D1","Workflows","Serialization"]',                     1),
('forum',   'migration_guy','Sharing experience migrating from Vercel to Cloudflare Workers. Deployment is faster, pricing is better, but DX for full-stack apps still has rough edges vs Next.js. Worth it overall.',                    '2026-04-26T17:15:00Z', 'neutral',  2,  '["Workers","Migration","Developer Experience"]',         1),
('forum',   'assets_help',  'How to serve static assets from Workers without using Pages? Documentation suggests the assets binding but there are very few working examples.',                                                               '2026-04-27T12:00:00Z', 'neutral',  4,  '["Workers","Static Assets","Documentation"]',            1),
('forum',   'json_pain',    'Workers AI Llama model gives inconsistent JSON outputs even with explicit prompting. Sometimes adds markdown fences, sometimes does not. Anyone have a reliable prompting strategy?',                          '2026-04-28T09:00:00Z', 'negative', 6,  '["Workers AI","LLM","JSON Parsing"]',                   1),
('forum',   'workflows_win','Finally got Cloudflare Workflows working after 2 days of debugging. Key insight nobody documents: each step return value MUST be JSON-serializable. Returning a D1 result object directly silently fails.',    '2026-04-29T14:45:00Z', 'neutral',  3,  '["Workflows","Documentation","D1"]',                    1);
